head.script:
// 전역 변수
scwin.memJson = $c.data.getMemInfo(); // 로그인 정보를 가져온다.
scwin.userClsCd = scwin.memJson.userClsCd;
// 사용자구분코드(01:그룹사구분코드(01:그룹사, 02:협력업체(운송), 03:선사, 04:화주, 05:자가운송업체, 06:렌터카(고객), 07:정비(고객))
if(scwin.userClsCd == null) scwin.userClsCd = "";

scwin.clntNo = scwin.memJson.clntNo; //거래처번호
scwin.clntNm = scwin.memJson.clntNm; //거래처명
scwin.loginId = scwin.memJson.userId;
scwin.nowDt = $c.date.getServerDateTime("yyyyMMdd");

scwin.cntlShowYn = false;
scwin.currDate = "";
scwin.currTime = "";
scwin.currDay = "";
scwin.tempHoliday = "";

scwin.hid_srchSelfTransCoCd = "";
scwin.hid_srchSelfTransCoNm = "";
scwin.cntrNo = "";

scwin.onpageload = function() {
    const codeOptions = [
        { grpCd : "SD136", compID : "gr_retrieve:crryinEdiFlag1" },
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.ondataload = function() { 
    let dltStr = "dlt_commonCodeSD136";
    let rowIdx = dlt_commonCodeSD136.insertRow(dlt_commonCodeSD136.getRowCount());

    dlt_commonCodeSD136.setCellData(rowIdx, "grpCd", "SD136");
    dlt_commonCodeSD136.setCellData(rowIdx, "cd", "99");
    dlt_commonCodeSD136.setCellData(rowIdx, "cdNm", "미등록");
    dlt_commonCodeSD136.setCellData(rowIdx, "fltrCd1", "");
    dlt_commonCodeSD136.setCellData(rowIdx, "fltrCd2", "");
    dlt_commonCodeSD136.setCellData(rowIdx, "fltrCd3", "");
    dlt_commonCodeSD136.setCellData(rowIdx, "sortSeq", 0)
    dlt_commonCodeSD136.setCellData(rowIdx, "cdDesc", "");
    dlt_commonCodeSD136.setCellData(rowIdx, "rowStatus", "R");
}

/**
 * UDC값
 */
scwin.onUdcCompleted = function() {
	scwin.f_getTime();

    if (scwin.userClsCd != "01") { //사용자 구분 : 05
        ed_srchSelfTransCoCd.setValue(scwin.clntNo);
        ed_srchSelfTransCoNm.setValue(scwin.clntNm);
        $c.gus.cfDisableObjects([ed_srchSelfTransCoCd,ed_srchSelfTransCoNm,btn_srchSelfTransCoCd]);
    } else {
        ed_srchSelfTransCoCd.setValue("");
        ed_srchSelfTransCoNm.setValue("");
        $c.gus.cfEnableObjects([ed_srchSelfTransCoCd,ed_srchSelfTransCoNm,btn_srchSelfTransCoCd]);
    }

    if (scwin.userClsCd == "01") {
        btn_Arv_Save.show();
        gr_retrieve.setColumnReadOnly("wrkPlNm", false);
        gr_retrieve.setHeaderClass("h_wrkPlNm", "txt-blue");
    } else {
        btn_Arv_Save.hide();
        gr_retrieve.setColumnReadOnly("wrkPlNm", true);
    }

    $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
    scwin.f_getEverLine();
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret = await $c.gus.cfValidate([tb_condition])
    if (!ret)
        return false;

    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 생성
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    let statFlag = true;    //컨테이너 유효성검사

    for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getCellData(i, 'impExpClsCd') == "D") {
            await $c.win.alert("On-Hire 건은 ON-HIRE 반입(반납)예정정보등록 화면에서 저장하세요");
            return false;
        }
    }

    if (await scwin.f_prefareCheck() == false) return;

    if (ds_retrieve.getModifiedIndex().length == 0) {
        await $c.win.alert($c.data.getMessage(MSG_CM_ERR_001, ["반입(반납) 예정 정보 등록(협력업체)"])); //변경된 정보가 없습니다.
        return;
    }

    if (!statFlag) {
        await $c.win.alert("체선일자가 현재일자보다 작습니다. 체선일자를 확인하십시오.");
        return;
    }

    let row = ds_retrieve.getRowPosition();
    let strOdrNo = ds_retrieve.getCellData(row, "odrNo");

    if (ds_retrieve.getCellData(row, "line") == "TSL" && strOdrNo.substring(1, 3) == "C2") {
        await $c.win.alert("TSL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    } else if (ds_retrieve.getCellData(row, "line") == "EAS" && strOdrNo.substring(1, 3) == "C2") {
        await $c.win.alert("EAS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    } else if (ds_retrieve.getCellData(row, "line") == "SWIL" && strOdrNo.substring(1, 3) == "C2") {
        if (ds_retrieve.getCellData(row, "wrkPlCd") == "6C09") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("SWL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!!");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "APL") {
        if (scwin.loginId == "150054" || scwin.loginId == "021710" || scwin.loginId == "070697" || scwin.loginId == "111897" || scwin.loginId == "140187") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "COH" && strOdrNo.substring(1, 3) == "C2") {
        if (scwin.loginId == "010028") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("COH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "YNK" && strOdrNo.substring(1, 3) == "C2") {
        if (scwin.loginId == "010028") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("YNK라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "SITC") {
        if (scwin.loginId == "072893" || scwin.loginId == "073294" || scwin.loginId == "030600" || scwin.loginId == "010028" || scwin.loginId == "021245") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("SITC라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (["NOLS", "TCLC", "SOFC", "TMSC", "TJM", "MAS", "JJS", "DWH", "RHT"].includes(ds_retrieve.getCellData(row, "line"))) {
        if (scwin.loginId == "040300" || scwin.loginId == "001234") {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("NOLS, TCLC, SOFC, TMSC, TJM, MAS, JJS, DWH, RHT 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "COS") {
        if (["150054", "021710", "070697", "111897", "140187", "100387"].includes(scwin.loginId)) {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("COS 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else if (ds_retrieve.getCellData(row, "line") == "MOL") {
        if (["150054", "021710", "070697", "111897", "140187"].includes(scwin.loginId)) {
            if (await $c.win.confirm("저장 하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("MOL 라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
            return false;
        }
    } else {
        if (await $c.win.confirm("저장 하시겠습니까?")) {
            $c.sbm.execute(sbm_regist);
        }
    }
};

//-------------------------------------------------------------------------
// 반납지 수정
//-------------------------------------------------------------------------
scwin.f_Arv_Save = async function() {
    if (await $c.win.confirm("저장 하시겠습니까?")) {
        $c.sbm.execute(sbm_ArvRegist);
    }
};

scwin.f_prefareCheck = async function() {
    for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getCellData(i, 'impExpClsCd') == "I") {
            let rowStatus = ds_retrieve.getRowStatus(i);
            if (rowStatus == "C" || rowStatus == "U") {
                if (!dscommon.cf_CheckCntrNo(ds_retrieve.getCellData(i, 'cntrNo'))) {
                    await $c.win.alert("유효한 컨테이너 번호가 아닙니다. 컨테이너 번호를 확인하십시요.");
                    return;
                }
            }
        }

        let rowStatus = ds_retrieve.getRowStatus(i);
        if (rowStatus == "U" || rowStatus == "C") {
            if (ds_retrieve.getCellData(i, 'cntrNo') == "") {
                await $c.win.alert("컨테이너 번호를 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, 'crryinoutIntendDt') == "") {
                await $c.win.alert("반납일을 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, 'crryinoutIntendHh') == "") {
                await $c.win.alert("반납시간을 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, "impExpClsCd") == "O") {
                if (ds_retrieve.getCellData(i, 'sealNo') == "") {
                    await $c.win.alert("봉인번호를 입력하세요!");
                    return false;
                }
            }
            if (ds_retrieve.getCellData(i, 'drvNm') == "") {
                await $c.win.alert("기사명을 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, 'drvTelNo') == "") {
                await $c.win.alert("연락처를 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, 'vehclNo') == "") {
                await $c.win.alert("차량을 입력하세요!");
                return false;
            }
            if (ds_retrieve.getCellData(i, 'vehclIdCardNo') == "") {
                await $c.win.alert("ID CARD를 입력하세요!");
                return false;
            }
            if (scwin.f_sameYn() &&
                ds_retrieve.getCellData(i, "impExpClsCd") == "I" &&
                ds_retrieve.getCellData(i, "fullEmptyClsCd") == "E" &&
                ds_retrieve.getCellData(i, "wrkPlCd") == "4C02" &&
                ds_retrieve.getCellData(i, "crryinoutClsCd") == "I") {

                if ((ds_retrieve.getCellData(i, "crryinoutIntendDt") > ds_retrieve.getCellData(i, "cntrRtrnDt")) ||
                    $c.gus.cfIsNull(ds_retrieve.getCellData(i, "cntrRtrnDt"))) {
                    await $c.win.alert("선사에서 반납기한 재지정 받으세요");
                    return false;
                }

            }

            //라인코드가 SITC이고, ODR_CTRL_CLS_CD = 3 인경우에 체선일자 체크
            if (ds_retrieve.getCellData(i, "line") == "SITC" && ds_retrieve.getCellData(i, "odrCtrlClsCd") == "3") {
                let sysDate = $c.date.getServerDateTime("yyyyMMdd");
                let demDate = ds_retrieve.getCellData(i, "cntrRtrnDt");
                if (!demDate == "") {
                    if (parseInt(demDate) < parseInt(sysDate)) { //20090801 < 20090918
                        //statFlag = false;
                        return false;
                    }
                } else {
                    await $c.win.alert("반납기한을 지정받으세요.");
                    ds_retrieve.setCellData(i, 'vehclNo', "");
                    ds_retrieve.setCellData(i, 'drvTelNo', "");
                    ds_retrieve.setCellData(i, 'drvNm', "");
                    ds_retrieve.setCellData(i, "vehclIdCardNo", "");
                    return false;
                }
            }
        }
    }
};

//-------------------------------------------------------------------------
// 조회조건 초기화
//-------------------------------------------------------------------------
scwin.f_SetInitCondVal = function() {
    $c.gus.cfInitObjects(tb_condition);
    scwin.hid_srchSelfTransCoCd="";
};

//-------------------------------------------------------------------------
// 코드 조회 팝업
//-------------------------------------------------------------------------
scwin.f_OpenPopup = async function(id, obj, param1, param2, pWinCloseTF, pWhere) {
    if (id == 'retrieveClntList') {
        pWhere = ",LOGISCLNT2";
        await udc_srchSelfTrans.cfCommonPopUp(scwin.udc_srchSelfTrans_callback,param1,param2,pWinCloseTF,null,null,null,null,pWhere,null,null,null,null);
    }
};

scwin.udc_srchSelfTrans_callback = function(rtnList) {
    if (!ed_srchSelfTransCoNm.options) ed_srchSelfTransCoNm.options = {};
    if (rtnList && rtnList[0] !== "N/A") {
        ed_srchSelfTransCoCd.setValue(rtnList[0]);  // 거래처 코드
        ed_srchSelfTransCoNm.setValue(rtnList[1]); // 거래처명
        ed_srchSelfTransCoNm.options.hidval = rtnList[1]; // 히든명
        scwin.hid_srchSelfTransCoCd=rtnList[0]; // 히든코드
    } else {
        ed_srchSelfTransCoCd.setValue("");
        ed_srchSelfTransCoNm.setValue("");
        scwin.hid_srchSelfTransCoCd="";
        ed_srchSelfTransCoNm.options.hidval = ""; // 히든명
    }
}

//-------------------------------------------------------------------------
// 조회 팝업
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = [];
    let cnt;
    let param = "";
    let pWhere = "";


    switch (disGubun) {
        case 1:
            scwin.f_scdRetrieve(); // ASIS에도 없는 함수를 호출함
            break;

        case 2:
            // 자가운송사 Popup  retrieveSelfClnt  
            pWhere = ",LOGISCLNT2";
            await udc_srchSelfTrans.cfCommonPopUp(scwin.udc_srchSelfTrans_callback, pCode, pName, "T", null, null, null, null, pWhere, null, null, null, null);
            break;

        case 3:
            // 자가운송사 Popup  retrieveSelfClnt
            scwin.cntrNo = pCode;
            pWhere = "";
            await udc_cntr.cfCommonPopUp(scwin.udc_cntr_callback, pCode, pName, "T", null, null, null, null, pWhere, null, null, null, null);
            break;

        case 4:
            // 반납지 Popup
            pWhere = null;
            pName = ds_retrieve.getCellData(gr_retrieve.getFocusedRowIndex(), "wrkPlNm");

            await udc_srchSelfTrans2.cfCommonPopUp(scwin.udc_srchSelfTrans2_callback, pCode, pName, "T", null, null, null, null, pWhere, null, null, null, null);
            break;

        default:
            break;
    }
};

scwin.udc_cntr_callback = function(rtnList) {
    if (!ed_srchSelfTransCoNm.options) ed_srchSelfTransCoNm.options = {};
    console.log(rtnList);
    if (rtnList != null && rtnList != "N/A") {
        ed_cntrNo.setValue(scwin.cntrNo);
        ed_srchSelfTransCoCd.setValue(rtnList[0]); //자가운송사코드
        ed_srchSelfTransCoNm.setValue(rtnList[1]); //자가운송사명
        ed_srchSelfTransCoNm.options.hidval = rtnList[1];//자가운송사명
        scwin.hid_srchSelfTransCoCd=rtnList[0]; //자가운송사코드
        ed_reqNo.setValue(rtnList[2]);
    } else {
        ed_srchSelfTransCoCd.setValue("");
        ed_srchSelfTransCoNm.setValue("");
        ed_srchSelfTransCoNm.options.hidval = "";
        scwin.hid_srchSelfTransCoCd="";
        ed_reqNo.setValue("");
    }
}

scwin.udc_srchSelfTrans2_callback = function(rtnList) {
    if (rtnList != null && rtnList[0] != 'N/A') {
        ds_retrieve.setCellData(gr_retrieve.getFocusedRowIndex(), "wrkPlCd", rtnList[0]); //작업장코드
        ds_retrieve.setCellData(gr_retrieve.getFocusedRowIndex(), "wrkPlNm", rtnList[1]); //작업장명
        if (ds_retrieve.getCellData(gr_retrieve.getFocusedRowIndex(), "wrkPlNm") == 'undefined') {
            ds_retrieve.setCellData(gr_retrieve.getFocusedRowIndex(), "wrkPlNm", '');
        }
    }
}

//-------------------------------------------------------------------------
// function name : f_crryInOutEDI
// function desc : 반출입예정정보EDI등록
//-------------------------------------------------------------------------
scwin.f_crryInOutEDI = async function(bAlertFlag, bSaveFlag, bTransferFlag, row, bDeleteFlag) {
    scwin.f_getTime();
    if (scwin.currTime > "1730" &&
        ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C01" &&
        (scwin.currDay == "0" || scwin.currDay == "6")
    ) {
        await $c.win.alert("17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), 'impExpClsCd') == "D") {
        await $c.win.alert("On-Hire 건은 ON-HIRE 반입(반납)예정정보등록 화면에서 등록하세요");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SITC") {
        if (scwin.loginId == "072893" || scwin.loginId == "073294" || scwin.loginId == "021245") {
            if (await $c.win.confirm("전송하시겠습니까?")) {
                $c.sbm.execute(sbm_regist);
            }
        } else {
            await $c.win.alert("SITC라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
            return false;
        }
        return false;
    }

    // PRISM OPEN에 의한 SITC, NOLS, SOFC, TCLC라인 코피노전송 막기
    if (["NOLS", "SOFC", "TCLC", "TMSC", "TJM", "MAS", "JJS", "DWH", "RHT"].includes(ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line"))) {
        await $c.win.alert(" NOLS, SOFC, TCLC, TMSC, TJM, MAS, JJS, DWH, RHT라인은 PRISM선사이므로 eTRANS에서 전송하세요 .");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "APL") {
        await $c.win.alert("APL라인 수출입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "COH" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2") {
        await $c.win.alert("COH라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "YNK" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2") {
        await $c.win.alert("YNK라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "COS" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2") {
        await $c.win.alert("COS라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "MOL" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2") {
        await $c.win.alert("MOL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!! 전화02-538-6000");
        return false;
    }

    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SWIL" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2" &&
        ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") != "6C09") {
        await $c.win.alert("SWL라인 수입화물 반출입처리는 KLNET통하여  처리하세요!!!");
        return false;
    }


    if (ds_retrieve.getRowCount() == 0) {
        return;
    }


    // 6C01 일때, 수입 수출 반입 반출 EMPTY 컨테이너는 코피노 금지
    if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C01" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "fullEmptyClsCd") == "E") {
        await $c.win.alert("담당자의 요청에 의해 COPINO 전송이 불가합니다.(신선대CY / EMPTY)");
        return false;
    }

    //수출인 경우 COPINO 자가 업체에서 못 날리도록 070322
    if ((ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "fullEmptyClsCd") == "F")) {
        // pcy
        if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2" &&
            ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SITC" &&
            ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P16") {
            // PCY - 이찬재대리요청- SITC,TSL && C4 && 6C09 이면 COPINO 전송할수 있게함 
            // 김현일대리 요청 - YNK, COH, SOFC, TCLC, NOLS 라인 추가
            // 이찬재과장 요청으로 반납지가 DPCT CY일 경우 자가 직반입가능하도록, 최미현차장님 요청으로 C4오더의 TSL/SOFC/TCLC/LOLS 라인 빠짐 2014.09.04 hurrah

        } else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SITC"
                // || ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TSL" 
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "YNK" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "COH"
                /* || ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SOFC" 
                   || ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TCLC"
                   || ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "NOLS" */
            ) &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C09")
        ) {
            // pass
        } else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C5" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SITC" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TSL" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "YNK" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "COH" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "SOFC" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TCLC" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "NOLS" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TMSC" // 2014.09.22 TMSC라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TJM" // 2015.05.21 TJM라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "MAS" // 2016.02.04 MAS라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "JJS" // 2016.04.11 JJS라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "DWH" // 2016.08.17 DWH라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "COS" // 2017.02.01 COS라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "MOL" // 2017.03.23 MOL라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "RHT" // 2017.04.05 RHT라인 추가
                ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "ONE" // 2018.03.08 ONE라인 추가
            ) &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C09")
        ) {
            // 허재석 사원요청으로 6P26 한진신항 터미널 코피노 전송가능하게 추가함    
            // 박경남 과장님 요청 BNCT 코피노 전송 추가             
        } else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "EVER" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "ITS" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "HTML" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "EMS" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "EGH" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "EMA" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "RCL") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P61" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P62" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P26" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P63"
            )
        ) {
            // pass
        } else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" &&
            ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "ESL"
        ) {
            // pass        
        } else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "XIDA" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TAT" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "TOP" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "KITO" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "GLS" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "MDS" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "PCW" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "HYSP" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "UFR") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C09")
        ) {
            // pass
        } 

        //박재율 대리님 요청 황창기 20150102 CHA150102000003 수출(C4,C5) 풀반입 KBCTCY 코피노 전송 가능하게 수정
        else if ((ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" ||
                ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C5") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "fullEmptyClsCd") == "F") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C01") &&
            (scwin.currDay != "0" && scwin.currDay != "6")
        ) {
            // pass C3오더 조회해서 제어검
        }
        // 이찬재 과장님 요청 RCL라인 C2오더 6P60반납시 코피노 전송 가능하게 수정 20150818 황창기         
        else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "RCL") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P60")
        ) {
            // pass
        }
        // 박경남 과장님 요청 RCL라인 C2오더 6P16반납시 코피노 전송 가능하게 수정 20190919 백진학      
        else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C2" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "line") == "RCL") &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6P16")
        ) {
            // pass
        }
        // 김태규 대리님 요청 C4오더 6C80반납시 코피노 전송 가능하게 수정 20211125      
        else if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo").substr(1, 2) == "C4" &&
            (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd") == "6C80")
        ) {
            // pass
        } else {
            await $c.win.alert("담당자의 요청에 의해 COPINO를 이용할 수 없습니다.\n\n 부산 : 각 라인 담당자 \n        수입 Empty반납은 ON-DOCK > 반출입사전정보입력을 이용하시기 바랍니다. \n\n 경기 : 031-380-9312\n\n 인천 : 032-890-9235\n\n 로 연락하시기 바랍니다.");
            return false;
        }
    }

    if (ds_retrieve.getRowStatus(ds_retrieve.getRowPosition()) == "C") {
        if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(), 'crryinEdiFlag1') != "" &&
            ds_retrieve.getCellData(ds_retrieve.getRowPosition(), 'crryinEdiFlag2') != "") {
            await $c.win.alert("반출입 예정 정보 등록을 하신후 반출입예정정보(COPINO EDI)등록을 하세요");
            return;
        }
    }
    if (!ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclNo")) {
        if (bAlertFlag) {
            await $c.win.alert("운송차량이 없습니다");
        }
        return false;
    }

    //저장,전송인경우
    if (bSaveFlag) {
        dma_searchEDI.removeAll();

        dma_searchEDI.set("qryClsCd", "1");
        dma_searchEDI.set("transWrkIndictNo", ds_results.getCellData(row, "onReqNo"));
        dma_searchEDI.set("odrNo", ds_results.getCellData(row, "odrNo"));
        dma_searchEDI.set("cntrSeq", ds_results.getCellData(row, "cntrSeq"));
        dma_searchEDI.set("wrkPathSeq", ds_results.getCellData(row, "wrkPathSeq"));
        dma_searchEDI.set("wrkStpSeq", ds_results.getCellData(row, "wrkStpSeq"));
        dma_searchEDI.set("vehclNo", ds_results.getCellData(row, "vehclNo"));
        dma_searchEDI.set("crryinoutDt", ds_results.getCellData(row, "wrkStDt"));
        dma_searchEDI.set("crryinDt", ds_results.getCellData(row, "wrkEndDt"));
        dma_searchEDI.set("cntrNo", ds_results.getCellData(row, "cntrNo"));
        dma_searchEDI.set("dptWrkPlCd", ds_results.getCellData(row, "dptWrkPlCd"));
        dma_searchEDI.set("arvWrkPlCd", ds_results.getCellData(row, "arvWrkPlCd"));
        dma_searchEDI.set("sndFlag", (bTransferFlag == true ? "1" : "0"));
        dma_searchEDI.set("delFlag", (bDeleteFlag == true ? "1" : "0"));

        //메시지 표시를 위해 저장(작업완료후 전송, 저장여부를 메시지로 표시해줌)
        scwin.gv_bEdiTransfer = bTransferFlag;
        $c.sbm.execute(sbm_saveEDI);
        return true;
    }

    let arrParam = [];
    arrParam[0] = [
        "1"				//조회구분 ("" : 운송작업지시, "1" : 반출입)
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "onReqNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "cntrSeq")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrWrkPathSeq")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "odrWrkStpSeq")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclIdCardNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "crryinoutIntendDt")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "crryinoutIntendDt")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "cntrNo")
        , ""
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlCd")
        , ""
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "wrkPlNm")
        , "N"
        , "CO"
        , "NO"
    ];

    arrParam[1] = [
        ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "onReqNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "vehclIdCardNo")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "drvNm")
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "drvTelNo")
        , ""
        , ""
        , ds_retrieve.getCellData(ds_retrieve.getRowPosition(), "crryinoutIntendDt")
        , "" 
    ];

    let data = {
        crryoutEdiType: "N",
        crryinEdiType: "CO",
        arrParam
    };

    let line = ds_retrieve.getCellData(row, "line");
    let crryinCyFlag = ds_retrieve.getCellData(row, 'crryinCyFlag');

    let pURL = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_21p.xml";
    let pURL2 = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_22p.xml";

    let popupUrl = pURL;
    if ((line == "EVER" || line == "ITS" || line == "EMS" || line == "LTXX" || line == "HTML") && crryinCyFlag == "C") {
        popupUrl = pURL2;
        let options = {
            id: "edi_popup",
            popupName: "반출입예정정보(EVER COPINO EDI)등록",
            width: 1100,
            height: 850
        };
        $c.win.openPopup(popupUrl, options, data);
    } else {
        popupUrl = pURL;
        let options = {
            id: "edi_popup",
            popupName: "반출입예정정보(COPINO EDI)등록",
            width: 1100,
            height: 850
        };
        $c.win.openPopup(popupUrl, options, data);
    }
    return true;
};

