scwin.f_chkOpenCommonPopUpText = function(inObj, codeObj, disGubun) {
    let pCode = "";
    let pName = "";

    if (inObj.getReadOnly() || (inObj.getValue() == inObj.options.hidVal))
        return;

    if (codeObj != null) {
        codeObj.setValue("");
    }

    pName = inObj.getValue();

    scwin.f_openCommonPopUp(disGubun, pCode, pName, 'T', 'T');
};

scwin.f_buttonControl = function() {
    scwin.f_getTime();
    let row = gr_retrieve.getFocusedRowIndex();

    //박재율 대리님 요청 황창기 20150102 CHA150102000003 수출(C4,C5) 풀반입 KBCTCY 코피노 전송 가능하게 수정
    if((ds_retrieve.getCellData(row,"odrNo").substr(1,2) == "C4")
		&&	(ds_retrieve.getCellData(row,"fullEmptyClsCd") == "F")
		&&	(ds_retrieve.getCellData(row,"wrkPlCd") == "6C01")
		&&	(ds_retrieve.getCellData(row,"line") != "SITC")
		&&	(ds_retrieve.getCellData(row,"line") != "NOLS")
		&&	(ds_retrieve.getCellData(row,"line") != "SOFC")
		&&	(ds_retrieve.getCellData(row,"line") != "TCLC")
		&&	(ds_retrieve.getCellData(row,"line") != "TMSC")
		&&	(ds_retrieve.getCellData(row,"line") != "TJM")
		&&	(ds_retrieve.getCellData(row,"line") != "MAS")
		&&	(ds_retrieve.getCellData(row,"line") != "JJS")
		&&	(ds_retrieve.getCellData(row,"line") != "APL")
		&&	(ds_retrieve.getCellData(row,"line") != "DWH")
		&&	(ds_retrieve.getCellData(row,"line") != "COS")
		&&	(ds_retrieve.getCellData(row,"line") != "MOL")
		&&	(ds_retrieve.getCellData(row,"line") != "RHT")
		&&	(ds_retrieve.getCellData(row,"line") != "ONE")		
		&&	(scwin.currTime <= "1700")
		&&  !(scwin.currDay == "0" || currDay == "6")
		&&	ds_retrieve.getCellData(row, "status")=="예정"		
	) {
   		$c.gus.cfEnableObjects([btn_carryingInOutEDI]);
	} else if($c.gus.cfIsNull(ds_retrieve.getCellData(row, 'crryinEdiFlag1'))) {
	    let line = ds_retrieve.getCellData(row,"line");
	    let crryinCyFlag = ds_retrieve.getCellData(row, 'crryinCyFlag');

		if((line=="EVER" || line=="ITS" || line=="EMS" || line=="LTXX" || line=="HTML") && crryinCyFlag =="C" && ds_retrieve.getCellData(row, "status")=="예정"){
			$c.gus.cfEnableObjects([btn_carryingInOutEDI]);	
		}else{
            if(ds_retrieve.getCellData(row,"odrNo").substr(1,2) == "C2"
            && ds_retrieve.getCellData(row,"line") == "SITC"
            && ds_retrieve.getCellData(row,"wrkPlCd") == "6P16"
            && ds_retrieve.getCellData(row, "status")=="예정"
	       ){
			    $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
	       }else{
		        //pcy
			    $c.gus.cfDisableObjects([btn_carryingInOutEDI]);	   
	       }
                //pcy
                //cfDisableObjects([btn_carryingInOutEDI]);
		}
	} else {
        if (ds_retrieve.getCellData(row, 'onPrgsStsCd') == "S" && ds_retrieve.getCellData(row, "status") == "예정") {
            $c.gus.cfEnableObjects([btn_carryingInOutEDI]);
        } else {
            //pcy
            $c.gus.cfDisableObjects([btn_carryingInOutEDI]);
        }
    }

    $c.gus.cfEnableObjects([btn_Save]);
};

