scwin.f_onoffCntlCheck = function(row) {
    if (scwin.f_sameYn() &&
        ds_retrieve.getCellData(row, "impExpClsCd") == "I" &&
        ds_retrieve.getCellData(row, "fullEmptyClsCd") == "E" &&
        ds_retrieve.getCellData(row, "wrkPlCd") == "4C02" &&
        ds_retrieve.getCellData(row, "crryinoutClsCd") == "I") {

        ds_retrieve.setCellData(row, "onoffCntlYn", 1);
    } else {
        ds_retrieve.setCellData(row, "onoffCntlYn", 0);
    }
};

