scwin.sbm_retreive_submitdone = async function (e) {
    if (ds_retrieve.getRowCount() != 0) {
        gr_retrieve.setFocusedCell(0, 0);
        totalRows.setValue(ds_retrieve.getRowCount())
        scwin.f_buttonControl();
    } else {
        await $c.win.alert(MSG_CM_ERR_003);
    }

    let target = 0;
    // 제어여부 체크되어있으면 메시지 보이도록 함.
    for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
        if (ds_retrieve.getCellData(i, "onoffCntlYn") == "1") {
            scwin.cntlShowYn = true;
            target = i;
            break;
        } else {
            scwin.cntlShowYn = false;
            target = i;
        }
    }
    if(scwin.f_sameYn() 
				&& ds_retrieve.getCellData(target, "impExpClsCd") == "I" 
				&& ds_retrieve.getCellData(target, "fullEmptyClsCd") == "E" 
				&& ds_retrieve.getCellData(target, "wrkPlCd") == "4C02"
				&& ds_retrieve.getCellData(target, "crryinoutClsCd") == "I"
				&& scwin.cntlShowYn
				) {
		await $c.win.alert("EVER EMPTY 반납은 담당자 승인이 필요합니다.\n승인까지 최대 30분정도 소요됩니다.");
		cntlYn.setStyle("display", "block");
        cntlYn.setValue("오류사유 : "+ds_retrieve.getCellData(target,"onoffCntlRsn"));
	}
	else {
		if(scwin.cntlShowYn) { 
			cntlYn.setStyle("display", "block");
            cntlYn.setValue("오류사유 : "+ds_retrieve.getCellData(target,"onoffCntlRsn"));
		}
		else {
			cntlYn.setStyle("display", "none");
		}
	}

  	//경인지역인 경우, 사용자 구분 : 01이 아닌경우(자가)에 하차증 발행버튼 보여줌
	if (ds_retrieve.getCellData(ds_retrieve.getRowPosition(),"wrkPlCd") == "4C02" && scwin.userClsCd != "01") {
		grp_printYn.setStyle("display", "block");
        gr_retrieve.setColumnVisible("chk", true);
	} else {
		grp_printYn.setStyle("display", "none");
        gr_retrieve.setColumnVisible("chk", false);
		//gr_retrieve.ColumnProp("chk", "Show") = "False";
	} 

	scwin.f_getTime();

  	if(scwin.currTime > "1700" && ds_retrieve.getCellData(ds_retrieve.getRowPosition(),"wrkPlCd")=="6C01") {
		btn_carryingInOutEDI.setValue("17:00 이후 KBCTCY는 Copino EDI전송불가");
		$c.gus.cfDisableObjects([btn_carryingInOutEDI]);
	}
};


