scwin.gr_retrieve_onviewchange = async function (info) {
    let row = info.rowIndex;
    let colid = gr_retrieve.getColumnID(info.colIndex);
    let olddata = info.oldValue;

    if (colid == "cntrNo") {
        if (ds_retrieve.getCellData(row, 'impExpClsCd') == "I") {
            if (!dscommon.cf_CheckCntrNo(ds_retrieve.getCellData(row, 'cntrNo'))) {
                await $c.win.alert("유효한 컨테이너 번호가 아닙니다. 컨테이너 번호를 확인하십시요.");
                gr_retrieve.setFocusedCell(row, 'cntrNo');
                gr_retrieve.setColumnReadOnly('cntrNo', false);
            }
        }
    }
    if (colid == "wrkPlNm") {
        if (ds_retrieve.getCellData(row, "wrkPlNm") != "") {
            scwin.f_openCommonPopUp(4, '', '', 'T', 'T');
        } else {
            ds_retrieve.setCellData(row, "wrkPlNm", "");
        }
    }
    scwin.f_onoffCntlCheck(row);

    if(colid == "chk"){
        for (let i = 0; i < ds_retrieve.getRowCount(); i++) {
            ds_retrieve.setCellData(i, "chk", 0);
        }

        if (colid == "chk" && info.newValue==1) {
            ds_retrieve.setCellData(row, "chk", 1);
        } else {
            ds_retrieve.setCellData(row, "chk", 0);
        }
    }
};

